import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Reading the whole line instead of just one token

        int bufferSize = 10;
        char[] buffer = new char[bufferSize]; // Buffer with fixed size

        // Copy only up to bufferSize characters from user input into the buffer
        for (int i = 0; i < Math.min(input.length(), bufferSize); i++) {
            buffer[i] = input.charAt(i); // Copying user input into the buffer
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

